# Python code to test that S'(t) = (1/π) Re[ζ'(1/2+it)/ζ(1/2+it)] is well-defined for t not a zero ordinate
import mpmath
import random
import json

mpmath.mp.dps = 30  # High precision

def compute_S_prime(t):
    """Compute S'(t) = (1/pi) * Re[zeta'(s)/zeta(s)] where s = 1/2 + it"""
    s = mpmath.mpc(0.5, t)
    zeta_val = mpmath.zeta(s)
    zeta_deriv = mpmath.zeta(s, derivative=1)

    if abs(zeta_val) < 1e-20:
        return None, abs(zeta_val)  # Too close to a zero

    ratio = zeta_deriv / zeta_val
    S_prime = float(mpmath.re(ratio)) / mpmath.pi
    return float(S_prime), float(abs(zeta_val))

# Get first few zero ordinates to avoid
known_zeros = [14.134725, 21.022040, 25.010858, 30.424876, 32.935062,
               37.586178, 40.918720, 43.327073, 48.005151, 49.773832]

def is_near_zero(t, tol=0.01):
    """Check if t is near a known zero ordinate"""
    for gamma in known_zeros:
        if abs(t - gamma) < tol:
            return True
    return False

# Test 1: Random t values away from zeros
trials = 0
passed = 0
max_error = None
counterexample = None
results = []

# Test random t values in various ranges
for _ in range(100):
    t = random.uniform(1, 100)
    if is_near_zero(t):
        continue

    trials += 1
    S_prime, zeta_mag = compute_S_prime(t)

    if S_prime is not None and abs(S_prime) < 1e10:  # Should be finite
        passed += 1
        results.append({'t': t, 'S_prime': S_prime, 'zeta_mag': zeta_mag})
    else:
        if counterexample is None:
            counterexample = {'t': t, 'S_prime': S_prime, 'zeta_mag': zeta_mag}

# Test 2: Values very close to (but not at) zeros - S' should be large but finite
for gamma in known_zeros[:5]:
    for delta in [0.1, 0.05, 0.02]:
        for sign in [-1, 1]:
            t = gamma + sign * delta
            trials += 1
            S_prime, zeta_mag = compute_S_prime(t)

            if S_prime is not None:  # Should be defined (though possibly large)
                passed += 1
                results.append({'t': t, 'near_zero': gamma, 'delta': delta, 'S_prime': S_prime})
            else:
                if counterexample is None:
                    counterexample = {'t': t, 'issue': 'undefined near zero', 'zeta_mag': zeta_mag}

# Test 3: Edge cases - small t
for t in [0.5, 1.0, 2.0, 5.0, 10.0]:
    trials += 1
    S_prime, zeta_mag = compute_S_prime(t)
    if S_prime is not None:
        passed += 1
    else:
        if counterexample is None:
            counterexample = {'t': t, 'issue': 'undefined at small t'}

# Test 4: Large t values
for _ in range(20):
    t = random.uniform(100, 500)
    trials += 1
    S_prime, zeta_mag = compute_S_prime(t)
    if S_prime is not None:
        passed += 1
    else:
        if counterexample is None:
            counterexample = {'t': t, 'issue': 'undefined at large t'}

# Compute max |S'| observed (as a sanity check)
if results:
    max_S_prime = max(abs(r.get('S_prime', 0)) for r in results if r.get('S_prime') is not None)
else:
    max_S_prime = None

summary = f"Tested S'(t) at {trials} points away from zero ordinates. {passed}/{trials} gave finite values. Max |S'| observed: {max_S_prime:.4f}" if max_S_prime else f"{passed}/{trials} passed"

output = {
    'passed': passed == trials,
    'trials': trials,
    'max_error': None,  # Not applicable - testing well-definedness, not numerical error
    'counterexample': counterexample,
    'summary': summary
}

print(json.dumps(output))
